1	/**
2	 * ACGLP Odoo Documentation - Branding Stylesheet
3	 * Version: 1.0.0
4	 * Last Updated: 2026-02-11
5	 *
6	 * This stylesheet provides consistent branding and styling for all
7	 * documentation generated for ACGLP Odoo modules.
8	 */
9	
10	/* ============================================================================
11	   Color Palette
12	   ============================================================================ */
13	
14	:root {
15	  /* Primary Colors */
16	  --acglp-primary: #2C3E50;        /* Dark blue-gray */
17	  --acglp-primary-light: #34495E;
18	  --acglp-primary-dark: #1A252F;
19	
20	  /* Accent Colors */
21	  --acglp-accent: #3498DB;          /* Bright blue */
22	  --acglp-accent-light: #5DADE2;
23	  --acglp-accent-dark: #2874A6;
24	
25	  /* Secondary Colors */
26	  --acglp-secondary: #16A085;       /* Teal */
27	  --acglp-secondary-light: #1ABC9C;
28	  --acglp-secondary-dark: #117A65;
29	
30	  /* Status Colors */
31	  --acglp-success: #27AE60;         /* Green */
32	  --acglp-warning: #F39C12;         /* Orange */
33	  --acglp-danger: #E74C3C;          /* Red */
34	  --acglp-info: #3498DB;            /* Blue */
35	
36	  /* Neutral Colors */
37	  --acglp-gray-100: #F8F9FA;
38	  --acglp-gray-200: #ECF0F1;
39	  --acglp-gray-300: #BDC3C7;
40	  --acglp-gray-400: #95A5A6;
41	  --acglp-gray-500: #7F8C8D;
42	  --acglp-gray-600: #5D6D7E;
43	  --acglp-gray-700: #34495E;
44	  --acglp-gray-800: #2C3E50;
45	  --acglp-gray-900: #1C2833;
46	
47	  /* Text Colors */
48	  --acglp-text-primary: #2C3E50;
49	  --acglp-text-secondary: #7F8C8D;
50	  --acglp-text-muted: #95A5A6;
51	
52	  /* Background Colors */
53	  --acglp-bg-primary: #FFFFFF;
54	  --acglp-bg-secondary: #F8F9FA;
55	  --acglp-bg-dark: #2C3E50;
56	
57	  /* Border Colors */
58	  --acglp-border-light: #ECF0F1;
59	  --acglp-border-default: #BDC3C7;
60	  --acglp-border-dark: #7F8C8D;
61	
62	  /* Odoo-specific Colors */
63	  --odoo-purple: #714B67;
64	  --odoo-purple-light: #875A7B;
65	  --odoo-purple-dark: #563845;
66	
67	  /* Spacing */
68	  --spacing-xs: 0.25rem;
69	  --spacing-sm: 0.5rem;
70	  --spacing-md: 1rem;
71	  --spacing-lg: 1.5rem;
72	  --spacing-xl: 2rem;
73	  --spacing-xxl: 3rem;
74	
75	  /* Border Radius */
76	  --border-radius-sm: 0.25rem;
77	  --border-radius-md: 0.375rem;
78	  --border-radius-lg: 0.5rem;
79	
80	  /* Shadows */
81	  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.05);
82	  --shadow-md: 0 4px 6px rgba(0, 0, 0, 0.1);
83	  --shadow-lg: 0 10px 15px rgba(0, 0, 0, 0.1);
84	
85	  /* Typography */
86	  --font-family-base: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
87	  --font-family-monospace: 'SFMono-Regular', Consolas, 'Liberation Mono', Menlo, Courier, monospace;
88	  --font-family-heading: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
89	}
90	
91	/* ============================================================================
92	   Base Styles
93	   ============================================================================ */
94	
95	body {
96	  font-family: var(--font-family-base);
97	  color: var(--acglp-text-primary);
98	  background-color: var(--acglp-bg-primary);
99	  line-height: 1.6;
100	  font-size: 16px;
101	}
102	
103	/* ============================================================================
104	   Typography
105	   ============================================================================ */
106	
107	h1, h2, h3, h4, h5, h6 {
108	  font-family: var(--font-family-heading);
109	  font-weight: 600;
110	  line-height: 1.3;
111	  margin-top: var(--spacing-xl);
112	  margin-bottom: var(--spacing-md);
113	  color: var(--acglp-primary);
114	}
115	
116	h1 {
117	  font-size: 2.5rem;
118	  border-bottom: 3px solid var(--acglp-accent);
119	  padding-bottom: var(--spacing-md);
120	  margin-bottom: var(--spacing-lg);
121	}
122	
123	h2 {
124	  font-size: 2rem;
125	  border-bottom: 2px solid var(--acglp-border-light);
126	  padding-bottom: var(--spacing-sm);
127	}
128	
129	h3 {
130	  font-size: 1.5rem;
131	  color: var(--acglp-primary-light);
132	}
133	
134	h4 {
135	  font-size: 1.25rem;
136	  color: var(--acglp-gray-700);
137	}
138	
139	h5 {
140	  font-size: 1.1rem;
141	  color: var(--acglp-gray-600);
142	}
143	
144	h6 {
145	  font-size: 1rem;
146	  color: var(--acglp-gray-600);
147	  font-weight: 600;
148	}
149	
150	p {
151	  margin-bottom: var(--spacing-md);
152	  color: var(--acglp-text-primary);
153	}
154	
155	a {
156	  color: var(--acglp-accent);
157	  text-decoration: none;
158	  transition: color 0.2s ease;
159	}
160	
161	a:hover {
162	  color: var(--acglp-accent-dark);
163	  text-decoration: underline;
164	}
165	
166	strong, b {
167	  font-weight: 600;
168	  color: var(--acglp-gray-800);
169	}
170	
171	em, i {
172	  font-style: italic;
173	}
174	
175	/* ============================================================================
176	   Code Blocks
177	   ============================================================================ */
178	
179	code {
180	  font-family: var(--font-family-monospace);
181	  font-size: 0.875rem;
182	  background-color: var(--acglp-gray-100);
183	  color: var(--acglp-danger);
184	  padding: 0.2rem 0.4rem;
185	  border-radius: var(--border-radius-sm);
186	}
187	
188	pre {
189	  font-family: var(--font-family-monospace);
190	  font-size: 0.875rem;
191	  background-color: var(--acglp-gray-900);
192	  color: var(--acglp-gray-100);
193	  padding: var(--spacing-md);
194	  border-radius: var(--border-radius-md);
195	  overflow-x: auto;
196	  margin-bottom: var(--spacing-md);
197	  border-left: 4px solid var(--acglp-accent);
198	}
199	
200	pre code {
201	  background-color: transparent;
202	  color: inherit;
203	  padding: 0;
204	}
205	
206	/* Language-specific code styling */
207	.language-python::before {
208	  content: 'Python';
209	  display: block;
210	  background-color: var(--acglp-accent);
211	  color: white;
212	  padding: var(--spacing-xs) var(--spacing-sm);
213	  margin: calc(-1 * var(--spacing-md)) calc(-1 * var(--spacing-md)) var(--spacing-sm);
214	  font-size: 0.75rem;
215	  font-weight: 600;
216	  text-transform: uppercase;
217	  letter-spacing: 0.5px;
218	}
219	
220	.language-xml::before,
221	.language-html::before {
222	  content: 'XML';
223	  display: block;
224	  background-color: var(--acglp-warning);
225	  color: white;
226	  padding: var(--spacing-xs) var(--spacing-sm);
227	  margin: calc(-1 * var(--spacing-md)) calc(-1 * var(--spacing-md)) var(--spacing-sm);
228	  font-size: 0.75rem;
229	  font-weight: 600;
230	  text-transform: uppercase;
231	}
232	
233	.language-bash::before,
234	.language-shell::before {
235	  content: 'Bash';
236	  display: block;
237	  background-color: var(--acglp-gray-700);
238	  color: white;
239	  padding: var(--spacing-xs) var(--spacing-sm);
240	  margin: calc(-1 * var(--spacing-md)) calc(-1 * var(--spacing-md)) var(--spacing-sm);
241	  font-size: 0.75rem;
242	  font-weight: 600;
243	  text-transform: uppercase;
244	}
245	
246	/* ============================================================================
247	   Tables
248	   ============================================================================ */
249	
250	table {
251	  width: 100%;
252	  border-collapse: collapse;
253	  margin-bottom: var(--spacing-lg);
254	  background-color: var(--acglp-bg-primary);
255	  box-shadow: var(--shadow-sm);
256	  border-radius: var(--border-radius-md);
257	  overflow: hidden;
258	}
259	
260	thead {
261	  background-color: var(--acglp-primary);
262	  color: white;
263	}
264	
265	thead th {
266	  padding: var(--spacing-md);
267	  text-align: left;
268	  font-weight: 600;
269	  text-transform: uppercase;
270	  font-size: 0.875rem;
271	  letter-spacing: 0.5px;
272	}
273	
274	tbody td {
275	  padding: var(--spacing-sm) var(--spacing-md);
276	  border-bottom: 1px solid var(--acglp-border-light);
277	}
278	
279	tbody tr:hover {
280	  background-color: var(--acglp-gray-100);
281	  transition: background-color 0.2s ease;
282	}
283	
284	tbody tr:last-child td {
285	  border-bottom: none;
286	}
287	
288	/* Striped tables */
289	.table-striped tbody tr:nth-child(even) {
290	  background-color: var(--acglp-gray-100);
291	}
292	
293	/* ============================================================================
294	   Lists
295	   ============================================================================ */
296	
297	ul, ol {
298	  margin-bottom: var(--spacing-md);
299	  padding-left: var(--spacing-xl);
300	}
301	
302	li {
303	  margin-bottom: var(--spacing-sm);
304	  color: var(--acglp-text-primary);
305	}
306	
307	ul li::marker {
308	  color: var(--acglp-accent);
309	}
310	
311	/* Task lists */
312	ul.task-list {
313	  list-style: none;
314	  padding-left: 0;
315	}
316	
317	ul.task-list li {
318	  padding-left: var(--spacing-lg);
319	  position: relative;
320	}
321	
322	ul.task-list li input[type="checkbox"] {
323	  position: absolute;
324	  left: 0;
325	  top: 0.25rem;
326	}
327	
328	/* ============================================================================
329	   Blockquotes
330	   ============================================================================ */
331	
332	blockquote {
333	  border-left: 4px solid var(--acglp-accent);
334	  background-color: var(--acglp-gray-100);
335	  padding: var(--spacing-md);
336	  margin: var(--spacing-md) 0;
337	  color: var(--acglp-text-secondary);
338	  border-radius: var(--border-radius-sm);
339	}
340	
341	blockquote p:last-child {
342	  margin-bottom: 0;
343	}
344	
345	/* ============================================================================
346	   Alerts and Callouts
347	   ============================================================================ */
348	
349	.alert {
350	  padding: var(--spacing-md);
351	  margin-bottom: var(--spacing-md);
352	  border: 1px solid transparent;
353	  border-radius: var(--border-radius-md);
354	  border-left-width: 4px;
355	}
356	
357	.alert-info {
358	  background-color: #D6EAF8;
359	  border-color: var(--acglp-info);
360	  color: #1F618D;
361	}
362	
363	.alert-success {
364	  background-color: #D5F4E6;
365	  border-color: var(--acglp-success);
366	  color: #186A3B;
367	}
368	
369	.alert-warning {
370	  background-color: #FCF3CF;
371	  border-color: var(--acglp-warning);
372	  color: #9A7D0A;
373	}
374	
375	.alert-danger {
376	  background-color: #F9EBEA;
377	  border-color: var(--acglp-danger);
378	  color: #922B21;
379	}
380	
381	/* Emoji-based callouts (for markdown) */
382	.callout-note {
383	  background-color: #D6EAF8;
384	  border-left: 4px solid var(--acglp-info);
385	  padding: var(--spacing-md);
386	  margin: var(--spacing-md) 0;
387	}
388	
389	.callout-tip {
390	  background-color: #D5F4E6;
391	  border-left: 4px solid var(--acglp-success);
392	  padding: var(--spacing-md);
393	  margin: var(--spacing-md) 0;
394	}
395	
396	.callout-warning {
397	  background-color: #FCF3CF;
398	  border-left: 4px solid var(--acglp-warning);
399	  padding: var(--spacing-md);
400	  margin: var(--spacing-md) 0;
401	}
402	
403	.callout-danger {
404	  background-color: #F9EBEA;
405	  border-left: 4px solid var(--acglp-danger);
406	  padding: var(--spacing-md);
407	  margin: var(--spacing-md) 0;
408	}
409	
410	/* ============================================================================
411	   Badges and Labels
412	   ============================================================================ */
413	
414	.badge {
415	  display: inline-block;
416	  padding: 0.25rem 0.5rem;
417	  font-size: 0.75rem;
418	  font-weight: 600;
419	  line-height: 1;
420	  text-align: center;
421	  white-space: nowrap;
422	  vertical-align: baseline;
423	  border-radius: var(--border-radius-sm);
424	}
425	
426	.badge-primary {
427	  background-color: var(--acglp-primary);
428	  color: white;
429	}
430	
431	.badge-secondary {
432	  background-color: var(--acglp-secondary);
433	  color: white;
434	}
435	
436	.badge-success {
437	  background-color: var(--acglp-success);
438	  color: white;
439	}
440	
441	.badge-warning {
442	  background-color: var(--acglp-warning);
443	  color: white;
444	}
445	
446	.badge-danger {
447	  background-color: var(--acglp-danger);
448	  color: white;
449	}
450	
451	.badge-info {
452	  background-color: var(--acglp-info);
453	  color: white;
454	}
455	
456	/* ============================================================================
457	   Buttons
458	   ============================================================================ */
459	
460	.btn {
461	  display: inline-block;
462	  padding: 0.5rem 1rem;
463	  font-size: 1rem;
464	  font-weight: 500;
465	  text-align: center;
466	  text-decoration: none;
467	  border: 1px solid transparent;
468	  border-radius: var(--border-radius-md);
469	  cursor: pointer;
470	  transition: all 0.2s ease;
471	}
472	
473	.btn-primary {
474	  background-color: var(--acglp-primary);
475	  color: white;
476	  border-color: var(--acglp-primary);
477	}
478	
479	.btn-primary:hover {
480	  background-color: var(--acglp-primary-dark);
481	  border-color: var(--acglp-primary-dark);
482	}
483	
484	.btn-secondary {
485	  background-color: var(--acglp-secondary);
486	  color: white;
487	  border-color: var(--acglp-secondary);
488	}
489	
490	.btn-secondary:hover {
491	  background-color: var(--acglp-secondary-dark);
492	  border-color: var(--acglp-secondary-dark);
493	}
494	
495	/* ============================================================================
496	   Cards
497	   ============================================================================ */
498	
499	.card {
500	  background-color: var(--acglp-bg-primary);
501	  border: 1px solid var(--acglp-border-light);
502	  border-radius: var(--border-radius-lg);
503	  box-shadow: var(--shadow-md);
504	  margin-bottom: var(--spacing-lg);
505	  overflow: hidden;
506	}
507	
508	.card-header {
509	  padding: var(--spacing-md);
510	  background-color: var(--acglp-gray-100);
511	  border-bottom: 1px solid var(--acglp-border-light);
512	  font-weight: 600;
513	  color: var(--acglp-primary);
514	}
515	
516	.card-body {
517	  padding: var(--spacing-md);
518	}
519	
520	.card-footer {
521	  padding: var(--spacing-md);
522	  background-color: var(--acglp-gray-100);
523	  border-top: 1px solid var(--acglp-border-light);
524	  font-size: 0.875rem;
525	  color: var(--acglp-text-secondary);
526	}
527	
528	/* ============================================================================
529	   Images and Media
530	   ============================================================================ */
531	
532	img {
533	  max-width: 100%;
534	  height: auto;
535	  border-radius: var(--border-radius-md);
536	  box-shadow: var(--shadow-sm);
537	}
538	
539	figure {
540	  margin: var(--spacing-lg) 0;
541	  text-align: center;
542	}
543	
544	figcaption {
545	  margin-top: var(--spacing-sm);
546	  font-size: 0.875rem;
547	  color: var(--acglp-text-secondary);
548	  font-style: italic;
549	}
550	
551	/* ============================================================================
552	   Documentation-Specific Styles
553	   ============================================================================ */
554	
555	/* Module header */
556	.module-header {
557	  background: linear-gradient(135deg, var(--acglp-primary) 0%, var(--acglp-primary-light) 100%);
558	  color: white;
559	  padding: var(--spacing-xl);
560	  border-radius: var(--border-radius-lg);
561	  margin-bottom: var(--spacing-xl);
562	}
563	
564	.module-header h1 {
565	  color: white;
566	  border-bottom: none;
567	  margin: 0;
568	}
569	
570	.module-metadata {
571	  display: grid;
572	  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
573	  gap: var(--spacing-md);
574	  margin-top: var(--spacing-md);
575	  font-size: 0.875rem;
576	}
577	
578	/* Status indicators */
579	.status-indicator {
580	  display: inline-block;
581	  width: 10px;
582	  height: 10px;
583	  border-radius: 50%;
584	  margin-right: var(--spacing-xs);
585	}
586	
587	.status-success {
588	  background-color: var(--acglp-success);
589	}
590	
591	.status-warning {
592	  background-color: var(--acglp-warning);
593	}
594	
595	.status-danger {
596	  background-color: var(--acglp-danger);
597	}
598	
599	.status-info {
600	  background-color: var(--acglp-info);
601	}
602	
603	/* Version badge */
604	.version-badge {
605	  background-color: var(--odoo-purple);
606	  color: white;
607	  padding: 0.25rem 0.75rem;
608	  border-radius: var(--border-radius-lg);
609	  font-size: 0.875rem;
610	  font-weight: 600;
611	}
612	
613	/* ============================================================================
614	   Print Styles
615	   ============================================================================ */
616	
617	@media print {
618	  body {
619	    background-color: white;
620	    color: black;
621	  }
622	
623	  a {
624	    color: black;
625	    text-decoration: underline;
626	  }
627	
628	  pre {
629	    background-color: #f5f5f5;
630	    color: black;
631	    border: 1px solid #ddd;
632	  }
633	
634	  .no-print {
635	    display: none;
636	  }
637	
638	  h1, h2, h3, h4, h5, h6 {
639	    page-break-after: avoid;
640	  }
641	
642	  table, figure {
643	    page-break-inside: avoid;
644	  }
645	}
646	
647	/* ============================================================================
648	   Responsive Design
649	   ============================================================================ */
650	
651	@media (max-width: 768px) {
652	  body {
653	    font-size: 14px;
654	  }
655	
656	  h1 {
657	    font-size: 2rem;
658	  }
659	
660	  h2 {
661	    font-size: 1.5rem;
662	  }
663	
664	  h3 {
665	    font-size: 1.25rem;
666	  }
667	
668	  table {
669	    font-size: 0.875rem;
670	  }
671	
672	  .module-metadata {
673	    grid-template-columns: 1fr;
674	  }
675	}
676	
677	/* ============================================================================
678	   Utility Classes
679	   ============================================================================ */
680	
681	.text-center {
682	  text-align: center;
683	}
684	
685	.text-right {
686	  text-align: right;
687	}
688	
689	.text-muted {
690	  color: var(--acglp-text-muted);
691	}
692	
693	.text-primary {
694	  color: var(--acglp-primary);
695	}
696	
697	.text-success {
698	  color: var(--acglp-success);
699	}
700	
701	.text-warning {
702	  color: var(--acglp-warning);
703	}
704	
705	.text-danger {
706	  color: var(--acglp-danger);
707	}
708	
709	.mb-0 {
710	  margin-bottom: 0;
711	}
712	
713	.mb-1 {
714	  margin-bottom: var(--spacing-sm);
715	}
716	
717	.mb-2 {
718	  margin-bottom: var(--spacing-md);
719	}
720	
721	.mb-3 {
722	  margin-bottom: var(--spacing-lg);
723	}
724	
725	.mt-0 {
726	  margin-top: 0;
727	}
728	
729	.mt-1 {
730	  margin-top: var(--spacing-sm);
731	}
732	
733	.mt-2 {
734	  margin-top: var(--spacing-md);
735	}
736	
737	.mt-3 {
738	  margin-top: var(--spacing-lg);
739	}
740

