/**
 * ACGLP Odoo Documentation - Branding Stylesheet
 * Version: 1.0.0
 * Last Updated: 2026-02-11
 *
 * This stylesheet provides consistent branding and styling for all
 * documentation generated for ACGLP Odoo modules.
 */

/* ============================================================================
   Color Palette
   ============================================================================ */

:root {
  /* Primary Colors */
  --acglp-primary: #2C3E50;        /* Dark blue-gray */
  --acglp-primary-light: #34495E;
  --acglp-primary-dark: #1A252F;

  /* Accent Colors */
  --acglp-accent: #3498DB;          /* Bright blue */
  --acglp-accent-light: #5DADE2;
  --acglp-accent-dark: #2874A6;

  /* Secondary Colors */
  --acglp-secondary: #16A085;       /* Teal */
  --acglp-secondary-light: #1ABC9C;
  --acglp-secondary-dark: #117A65;

  /* Status Colors */
  --acglp-success: #27AE60;         /* Green */
  --acglp-warning: #F39C12;         /* Orange */
  --acglp-danger: #E74C3C;          /* Red */
  --acglp-info: #3498DB;            /* Blue */

  /* Neutral Colors */
  --acglp-gray-100: #F8F9FA;
  --acglp-gray-200: #ECF0F1;
  --acglp-gray-300: #BDC3C7;
  --acglp-gray-400: #95A5A6;
  --acglp-gray-500: #7F8C8D;
  --acglp-gray-600: #5D6D7E;
  --acglp-gray-700: #34495E;
  --acglp-gray-800: #2C3E50;
  --acglp-gray-900: #1C2833;

  /* Text Colors */
  --acglp-text-primary: #2C3E50;
  --acglp-text-secondary: #7F8C8D;
  --acglp-text-muted: #95A5A6;

  /* Background Colors */
  --acglp-bg-primary: #FFFFFF;
  --acglp-bg-secondary: #F8F9FA;
  --acglp-bg-dark: #2C3E50;

  /* Border Colors */
  --acglp-border-light: #ECF0F1;
  --acglp-border-default: #BDC3C7;
  --acglp-border-dark: #7F8C8D;

  /* Odoo-specific Colors */
  --odoo-purple: #714B67;
  --odoo-purple-light: #875A7B;
  --odoo-purple-dark: #563845;

  /* Spacing */
  --spacing-xs: 0.25rem;
  --spacing-sm: 0.5rem;
  --spacing-md: 1rem;
  --spacing-lg: 1.5rem;
  --spacing-xl: 2rem;
  --spacing-xxl: 3rem;

  /* Border Radius */
  --border-radius-sm: 0.25rem;
  --border-radius-md: 0.375rem;
  --border-radius-lg: 0.5rem;

  /* Shadows */
  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.05);
  --shadow-md: 0 4px 6px rgba(0, 0, 0, 0.1);
  --shadow-lg: 0 10px 15px rgba(0, 0, 0, 0.1);

  /* Typography */
  --font-family-base: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
  --font-family-monospace: 'SFMono-Regular', Consolas, 'Liberation Mono', Menlo, Courier, monospace;
  --font-family-heading: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
}

/* ============================================================================
   Base Styles
   ============================================================================ */

body {
  font-family: var(--font-family-base);
  color: var(--acglp-text-primary);
  background-color: var(--acglp-bg-primary);
  line-height: 1.6;
  font-size: 16px;
}

/* ============================================================================
   Typography
   ============================================================================ */

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-family-heading);
  font-weight: 600;
  line-height: 1.3;
  margin-top: var(--spacing-xl);
  margin-bottom: var(--spacing-md);
  color: var(--acglp-primary);
}

h1 {
  font-size: 2.5rem;
  border-bottom: 3px solid var(--acglp-accent);
  padding-bottom: var(--spacing-md);
  margin-bottom: var(--spacing-lg);
}

h2 {
  font-size: 2rem;
  border-bottom: 2px solid var(--acglp-border-light);
  padding-bottom: var(--spacing-sm);
}

h3 {
  font-size: 1.5rem;
  color: var(--acglp-primary-light);
}

h4 {
  font-size: 1.25rem;
  color: var(--acglp-gray-700);
}

h5 {
  font-size: 1.1rem;
  color: var(--acglp-gray-600);
}

h6 {
  font-size: 1rem;
  color: var(--acglp-gray-600);
  font-weight: 600;
}

p {
  margin-bottom: var(--spacing-md);
  color: var(--acglp-text-primary);
}

a {
  color: var(--acglp-accent);
  text-decoration: none;
  transition: color 0.2s ease;
}

a:hover {
  color: var(--acglp-accent-dark);
  text-decoration: underline;
}

strong, b {
  font-weight: 600;
  color: var(--acglp-gray-800);
}

em, i {
  font-style: italic;
}

/* ============================================================================
   Code Blocks
   ============================================================================ */

code {
  font-family: var(--font-family-monospace);
  font-size: 0.875rem;
  background-color: var(--acglp-gray-100);
  color: var(--acglp-danger);
  padding: 0.2rem 0.4rem;
  border-radius: var(--border-radius-sm);
}

pre {
  font-family: var(--font-family-monospace);
  font-size: 0.875rem;
  background-color: var(--acglp-gray-900);
  color: var(--acglp-gray-100);
  padding: var(--spacing-md);
  border-radius: var(--border-radius-md);
  overflow-x: auto;
  margin-bottom: var(--spacing-md);
  border-left: 4px solid var(--acglp-accent);
}

pre code {
  background-color: transparent;
  color: inherit;
  padding: 0;
}

/* Language-specific code styling */
.language-python::before {
  content: 'Python';
  display: block;
  background-color: var(--acglp-accent);
  color: white;
  padding: var(--spacing-xs) var(--spacing-sm);
  margin: calc(-1 * var(--spacing-md)) calc(-1 * var(--spacing-md)) var(--spacing-sm);
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.language-xml::before,
.language-html::before {
  content: 'XML';
  display: block;
  background-color: var(--acglp-warning);
  color: white;
  padding: var(--spacing-xs) var(--spacing-sm);
  margin: calc(-1 * var(--spacing-md)) calc(-1 * var(--spacing-md)) var(--spacing-sm);
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
}

.language-bash::before,
.language-shell::before {
  content: 'Bash';
  display: block;
  background-color: var(--acglp-gray-700);
  color: white;
  padding: var(--spacing-xs) var(--spacing-sm);
  margin: calc(-1 * var(--spacing-md)) calc(-1 * var(--spacing-md)) var(--spacing-sm);
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
}

/* ============================================================================
   Tables
   ============================================================================ */

table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: var(--spacing-lg);
  background-color: var(--acglp-bg-primary);
  box-shadow: var(--shadow-sm);
  border-radius: var(--border-radius-md);
  overflow: hidden;
}

thead {
  background-color: var(--acglp-primary);
  color: white;
}

thead th {
  padding: var(--spacing-md);
  text-align: left;
  font-weight: 600;
  text-transform: uppercase;
  font-size: 0.875rem;
  letter-spacing: 0.5px;
}

tbody td {
  padding: var(--spacing-sm) var(--spacing-md);
  border-bottom: 1px solid var(--acglp-border-light);
}

tbody tr:hover {
  background-color: var(--acglp-gray-100);
  transition: background-color 0.2s ease;
}

tbody tr:last-child td {
  border-bottom: none;
}

/* Striped tables */
.table-striped tbody tr:nth-child(even) {
  background-color: var(--acglp-gray-100);
}

/* ============================================================================
   Lists
   ============================================================================ */

ul, ol {
  margin-bottom: var(--spacing-md);
  padding-left: var(--spacing-xl);
}

li {
  margin-bottom: var(--spacing-sm);
  color: var(--acglp-text-primary);
}

ul li::marker {
  color: var(--acglp-accent);
}

/* Task lists */
ul.task-list {
  list-style: none;
  padding-left: 0;
}

ul.task-list li {
  padding-left: var(--spacing-lg);
  position: relative;
}

ul.task-list li input[type="checkbox"] {
  position: absolute;
  left: 0;
  top: 0.25rem;
}

/* ============================================================================
   Blockquotes
   ============================================================================ */

blockquote {
  border-left: 4px solid var(--acglp-accent);
  background-color: var(--acglp-gray-100);
  padding: var(--spacing-md);
  margin: var(--spacing-md) 0;
  color: var(--acglp-text-secondary);
  border-radius: var(--border-radius-sm);
}

blockquote p:last-child {
  margin-bottom: 0;
}

/* ============================================================================
   Alerts and Callouts
   ============================================================================ */

.alert {
  padding: var(--spacing-md);
  margin-bottom: var(--spacing-md);
  border: 1px solid transparent;
  border-radius: var(--border-radius-md);
  border-left-width: 4px;
}

.alert-info {
  background-color: #D6EAF8;
  border-color: var(--acglp-info);
  color: #1F618D;
}

.alert-success {
  background-color: #D5F4E6;
  border-color: var(--acglp-success);
  color: #186A3B;
}

.alert-warning {
  background-color: #FCF3CF;
  border-color: var(--acglp-warning);
  color: #9A7D0A;
}

.alert-danger {
  background-color: #F9EBEA;
  border-color: var(--acglp-danger);
  color: #922B21;
}

/* Emoji-based callouts (for markdown) */
.callout-note {
  background-color: #D6EAF8;
  border-left: 4px solid var(--acglp-info);
  padding: var(--spacing-md);
  margin: var(--spacing-md) 0;
}

.callout-tip {
  background-color: #D5F4E6;
  border-left: 4px solid var(--acglp-success);
  padding: var(--spacing-md);
  margin: var(--spacing-md) 0;
}

.callout-warning {
  background-color: #FCF3CF;
  border-left: 4px solid var(--acglp-warning);
  padding: var(--spacing-md);
  margin: var(--spacing-md) 0;
}

.callout-danger {
  background-color: #F9EBEA;
  border-left: 4px solid var(--acglp-danger);
  padding: var(--spacing-md);
  margin: var(--spacing-md) 0;
}

/* ============================================================================
   Badges and Labels
   ============================================================================ */

.badge {
  display: inline-block;
  padding: 0.25rem 0.5rem;
  font-size: 0.75rem;
  font-weight: 600;
  line-height: 1;
  text-align: center;
  white-space: nowrap;
  vertical-align: baseline;
  border-radius: var(--border-radius-sm);
}

.badge-primary {
  background-color: var(--acglp-primary);
  color: white;
}

.badge-secondary {
  background-color: var(--acglp-secondary);
  color: white;
}

.badge-success {
  background-color: var(--acglp-success);
  color: white;
}

.badge-warning {
  background-color: var(--acglp-warning);
  color: white;
}

.badge-danger {
  background-color: var(--acglp-danger);
  color: white;
}

.badge-info {
  background-color: var(--acglp-info);
  color: white;
}

/* ============================================================================
   Buttons
   ============================================================================ */

.btn {
  display: inline-block;
  padding: 0.5rem 1rem;
  font-size: 1rem;
  font-weight: 500;
  text-align: center;
  text-decoration: none;
  border: 1px solid transparent;
  border-radius: var(--border-radius-md);
  cursor: pointer;
  transition: all 0.2s ease;
}

.btn-primary {
  background-color: var(--acglp-primary);
  color: white;
  border-color: var(--acglp-primary);
}

.btn-primary:hover {
  background-color: var(--acglp-primary-dark);
  border-color: var(--acglp-primary-dark);
}

.btn-secondary {
  background-color: var(--acglp-secondary);
  color: white;
  border-color: var(--acglp-secondary);
}

.btn-secondary:hover {
  background-color: var(--acglp-secondary-dark);
  border-color: var(--acglp-secondary-dark);
}

/* ============================================================================
   Cards
   ============================================================================ */

.card {
  background-color: var(--acglp-bg-primary);
  border: 1px solid var(--acglp-border-light);
  border-radius: var(--border-radius-lg);
  box-shadow: var(--shadow-md);
  margin-bottom: var(--spacing-lg);
  overflow: hidden;
}

.card-header {
  padding: var(--spacing-md);
  background-color: var(--acglp-gray-100);
  border-bottom: 1px solid var(--acglp-border-light);
  font-weight: 600;
  color: var(--acglp-primary);
}

.card-body {
  padding: var(--spacing-md);
}

.card-footer {
  padding: var(--spacing-md);
  background-color: var(--acglp-gray-100);
  border-top: 1px solid var(--acglp-border-light);
  font-size: 0.875rem;
  color: var(--acglp-text-secondary);
}

/* ============================================================================
   Images and Media
   ============================================================================ */

img {
  max-width: 100%;
  height: auto;
  border-radius: var(--border-radius-md);
  box-shadow: var(--shadow-sm);
}

figure {
  margin: var(--spacing-lg) 0;
  text-align: center;
}

figcaption {
  margin-top: var(--spacing-sm);
  font-size: 0.875rem;
  color: var(--acglp-text-secondary);
  font-style: italic;
}

/* ============================================================================
   Documentation-Specific Styles
   ============================================================================ */

/* Module header */
.module-header {
  background: linear-gradient(135deg, var(--acglp-primary) 0%, var(--acglp-primary-light) 100%);
  color: white;
  padding: var(--spacing-xl);
  border-radius: var(--border-radius-lg);
  margin-bottom: var(--spacing-xl);
}

.module-header h1 {
  color: white;
  border-bottom: none;
  margin: 0;
}

.module-metadata {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: var(--spacing-md);
  margin-top: var(--spacing-md);
  font-size: 0.875rem;
}

/* Status indicators */
.status-indicator {
  display: inline-block;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  margin-right: var(--spacing-xs);
}

.status-success {
  background-color: var(--acglp-success);
}

.status-warning {
  background-color: var(--acglp-warning);
}

.status-danger {
  background-color: var(--acglp-danger);
}

.status-info {
  background-color: var(--acglp-info);
}

/* Version badge */
.version-badge {
  background-color: var(--odoo-purple);
  color: white;
  padding: 0.25rem 0.75rem;
  border-radius: var(--border-radius-lg);
  font-size: 0.875rem;
  font-weight: 600;
}

/* ============================================================================
   Print Styles
   ============================================================================ */

@media print {
  body {
    background-color: white;
    color: black;
  }

  a {
    color: black;
    text-decoration: underline;
  }

  pre {
    background-color: #f5f5f5;
    color: black;
    border: 1px solid #ddd;
  }

  .no-print {
    display: none;
  }

  h1, h2, h3, h4, h5, h6 {
    page-break-after: avoid;
  }

  table, figure {
    page-break-inside: avoid;
  }
}

/* ============================================================================
   Responsive Design
   ============================================================================ */

@media (max-width: 768px) {
  body {
    font-size: 14px;
  }

  h1 {
    font-size: 2rem;
  }

  h2 {
    font-size: 1.5rem;
  }

  h3 {
    font-size: 1.25rem;
  }

  table {
    font-size: 0.875rem;
  }

  .module-metadata {
    grid-template-columns: 1fr;
  }
}

/* ============================================================================
   Utility Classes
   ============================================================================ */

.text-center {
  text-align: center;
}

.text-right {
  text-align: right;
}

.text-muted {
  color: var(--acglp-text-muted);
}

.text-primary {
  color: var(--acglp-primary);
}

.text-success {
  color: var(--acglp-success);
}

.text-warning {
  color: var(--acglp-warning);
}

.text-danger {
  color: var(--acglp-danger);
}

.mb-0 {
  margin-bottom: 0;
}

.mb-1 {
  margin-bottom: var(--spacing-sm);
}

.mb-2 {
  margin-bottom: var(--spacing-md);
}

.mb-3 {
  margin-bottom: var(--spacing-lg);
}

.mt-0 {
  margin-top: 0;
}

.mt-1 {
  margin-top: var(--spacing-sm);
}

.mt-2 {
  margin-top: var(--spacing-md);
}

.mt-3 {
  margin-top: var(--spacing-lg);
}
